#' Catch and Translate RTMB Errors into User-Friendly Messages
#'
#' @description
#' This internal helper function wraps an R expression in a [tryCatch()] block to
#' capture cryptic error messages generated by the RTMB automatic differentiation
#' engine or C++ backend, translating them into descriptive hints in Japanese.
#'
#' @details
#' It uses regular expressions to categorize common RTMB failure modes, such as:
#' \itemize{
#'   \item **Missing Objects/Functions**: Detects if a variable or a specific distribution
#'   function (e.g., `normal_lpdf`) is missing from the environment.
#'   \item **Index Errors**: Identifies subscript out of bounds errors.
#'   \item **AD Type Destruction**: Catches the "lost class attribute" error, often caused
#'   by incorrect initialization of vectors (e.g., using `numeric(N)` and partial assignment
#'   inside loops).
#'   \item **Matrix Dimension Mismatch**: Identifies non-conformable arguments in
#'   matrix multiplication.
#' }
#'
#' @param expr An R expression to be evaluated, typically representing the logic within
#' a specific model block.
#' @param block_name A character string identifying the context of the error
#' (e.g., "parameters", "model", "transform", or "generate").
#'
#' @return The result of evaluating the \code{expr}. If an error occurs, it throws
#' a formatted [stop()] message.
#'
#' @keywords internal
with_rtmb_error_handling <- function(expr, block_name) {
  tryCatch({
    expr
  }, error = function(e) {
    msg <- conditionMessage(e)
    call_expr <- conditionCall(e)

    call_str <- if (!is.null(call_expr)) {
      code_snippet <- paste(deparse(call_expr), collapse = " ")
      if (nchar(code_snippet) > 100) paste0(substr(code_snippet, 1, 97), "...") else code_snippet
    } else {
      "不明な箇所"
    }

    # 1. 存在しない変数の使用
    if (grepl("object '.*' not found", msg) || grepl("オブジェクト '.*' がありません", msg)) {
      var_name <- sub(".*(?:object|オブジェクト) '(.*)'.*", "\\1", msg)
      stop(sprintf("【%s ブロックのエラー】存在しない変数 '%s' が使われています。\n  [発生箇所]: %s\n  * data または parameters に含まれているか確認してください。",
                   block_name, var_name, call_str), call. = FALSE)
    }

    # 1. 存在しない関数の使用
    if (grepl("could not find function", msg) || grepl("関数 .* を見つけることができません", msg) || grepl("関数 .* が見つかりません", msg)) {
      func_name <- sub(".*(?:function|関数) [\"']?(.*?)[\"']? ?(?:を見つける|が見つかり|could not).*", "\\1", msg)
      stop(sprintf("【%s ブロックのエラー】存在しない関数 '%s' が使われています。\n  [発生箇所]: %s",
                   block_name, func_name, call_str), call. = FALSE)
    }

    # 2. インデックスエラー
    if (grepl("subscript out of bounds", msg) || grepl("範囲外", msg)) {
      stop(sprintf("【%s ブロックのエラー】配列や行列のインデックスが範囲外です。\n  [発生箇所]: %s",
                   block_name, call_str), call. = FALSE)
    }

    # 3. advector の破壊 / 型変換の失敗
    if (grepl("lost class attribute", msg) || grepl("Invalid argument to 'advector'", msg) ||
        grepl("数学関数に非数値引数", msg) || grepl("non-numeric argument to mathematical function", msg)) {
      stop(sprintf("【%s ブロックのエラー】自動微分(AD)の型が破壊されたか、不正な型の計算が行われました。\n  [発生箇所]: %s\n  * 原因例: numeric(N)等で初期化した空ベクトルへの代入 (型がリスト化してしまいます)。\n  * 対策: 計算をベクトル化するか、advector(numeric(N)) で初期化してください。",
                   block_name, call_str), call. = FALSE)
    }

    # 4. 行列の次元の不一致
    if (grepl("non-conformable arguments", msg) || grepl("適合しない", msg) || grepl("非等角", msg)) {
      stop(sprintf("【%s ブロックのエラー】行列の掛け算(%%*%%)等で次元が合っていません。\n  [発生箇所]: %s",
                   block_name, call_str), call. = FALSE)
    }

    # その他のエラー
    stop(sprintf("【%s ブロックのエラー】\n  [メッセージ]: %s\n  [発生箇所]: %s",
                 block_name, msg, call_str), call. = FALSE)
  })
}
#' RTMB_Model インスタンスを生成するラッパー関数
#'
#' @description
#' ユーザーが定義したデータ、およびモデルコード（尤度や事前分布）を結合し、
#' ベイズ推論（MCMC, VB, MAP推定）を実行するための `RTMB_Model` (R6クラス) インスタンスを生成します。
#'
#' @param data モデルで使用する観測データや定数（サンプルサイズなど）を含む名前付きリスト。
#' @param code `rtmb_code(...)` で記述されたモデル定義ブロック（data, parameters, model, transform, generate を含む）。
#' @param par_names 各パラメータの次元に対応する具体的な変数名のリスト（省略可能）。
#' @param init パラメータの初期値のリストまたは数値ベクトル（省略可能）。指定しない場合は自動でランダムに初期化されます。
#' @param view `summary()` などで結果を出力する際、優先して上部に表示したいパラメータ名の文字ベクトル（省略可能）。
#'
#' @return モデルのコンパイルと事前テストが完了した `RTMB_Model` クラスのインスタンス。
#' @export
rtmb_model <- function(data, code, par_names = list(), init = NULL, view = NULL) {

  if (!"parameters" %in% names(code)) stop("code の中に 'parameters = { ... }' ブロックが必要です。")
  if (!"model" %in% names(code)) stop("code の中に 'model = { ... }' ブロックが必要です。")

  # --- 1. Data ブロックの静的検証 (オプション) ---
  if ("data" %in% names(code)) {
    data_vars <- all.vars(code$data)
    missing_data <- setdiff(data_vars, names(data))
    if (length(missing_data) > 0) {
      stop(sprintf("【data ブロックの宣言エラー】\n宣言された変数 '%s' が、渡された data リスト(%s)の中に存在しません。",
                   missing_data[1], paste(names(data), collapse = ", ")), call. = FALSE)
    }
  }

  # --- 2. Parameters ブロックの静的検証と評価 ---
  param_exprs <- as.list(code$parameters)[-1]
  evaluated_par_list <- list()
  eval_env <- list2env(data, parent = parent.env(globalenv()))

  for (e in param_exprs) {
    if (is.null(e)) next
    if (is.call(e) && (identical(e[[1]], as.name("=")) || identical(e[[1]], as.name("<-")))) {
      v_name <- as.character(e[[2]])
      d_expr <- e[[3]]

      # ★ Rのスコープに頼らない最強のAST静的解析 ★
      # all.vars は関数名(Dimなど)を除外し、使われている純粋な変数名だけを抽出します
      used_vars <- all.vars(d_expr)
      missing_vars <- setdiff(used_vars, names(data))

      if (length(missing_vars) > 0) {
        stop(sprintf("【parameters ブロックのエラー】\n存在しない変数 '%s' が使われています。\n  [発生箇所]: %s\n  * data リストに含まれているか確認してください。",
                     missing_vars[1], paste(deparse(e), collapse = " ")), call. = FALSE)
      }

      # チェックを通過したものだけを安全に評価
      evaluated_par_list[[v_name]] <- eval(d_expr, envir = eval_env)
    } else {
      stop("parametersブロックの書式エラー: ", paste(deparse(e), collapse = " "))
    }
  }

  # --- 3. 動的コンパイル (model, transform, generate) ---
  user_env <- if (!is.null(code$env)) code$env else parent.frame()

  comp_model <- eval(bquote(model_code(.(code$model), env = user_env)))

  comp_transform <- NULL
  if ("transform" %in% names(code)) {
    comp_transform <- eval(bquote(transform_code(.(code$transform), env = user_env)))
  }

  comp_generate <- NULL
  if ("generate" %in% names(code)) {
    comp_generate <- eval(bquote(transform_code(.(code$generate), env = user_env)))
  }

  # --- 4. 事前テスト (Sandbox実行) ---
  cat("Pre-checking model code...\n")
  set.seed(12345)

  test_unc_list <- lapply(evaluated_par_list, function(p) {
    rnorm(p$unc_length, mean = 0, sd = 0.1)
  })
  test_para <- to_constrained(test_unc_list, evaluated_par_list)

  for (name in names(evaluated_par_list)) {
    p <- evaluated_par_list[[name]]
    if (!is.null(p$init)) {
      val <- rep(p$init, length.out = p$length)
      if (any(is.na(val))) {
        val[is.na(val)] <- as.numeric(test_para[[name]])[is.na(val)]
      }
      test_para[[name]] <- array(val, dim = p$dim)
    }
  }

  if (!is.null(comp_transform)) {
    test_tran <- BayesRTMB:::with_rtmb_error_handling({ comp_transform(data, test_para) }, "transform")
    if (is.list(test_tran)) test_para <- c(test_para, test_tran)
  }

  BayesRTMB:::with_rtmb_error_handling({ comp_model(data, test_para) }, "model")

  if (!is.null(comp_generate)) {
    BayesRTMB:::with_rtmb_error_handling({ comp_generate(data, test_para) }, "generate")
  }

  # --- 5. 実行用安全ラッパーの作成 ---
  safe_model <- function(dat, para) { BayesRTMB:::with_rtmb_error_handling({ comp_model(dat, para) }, "model") }

  safe_transformed <- NULL
  if (!is.null(comp_transform)) {
    safe_transformed <- function(dat, para) {
      res <- BayesRTMB:::with_rtmb_error_handling({ comp_transform(dat, para) }, "transform")
      if (!is.list(res)) stop("戻り値は「名前付きリスト (list)」である必要があります。")
      res
    }
    attr(safe_transformed, "raw_expr") <- code$transform
  }

  safe_generate <- NULL
  if (!is.null(comp_generate)) {
    safe_generate <- function(dat, para) {
      res <- BayesRTMB:::with_rtmb_error_handling({ comp_generate(dat, para) }, "generate")
      if (!is.list(res)) stop("戻り値は「名前付きリスト (list)」である必要があります。")
      res
    }
    attr(safe_generate, "raw_expr") <- code$generate
  }

  # --- 6. R6クラスへ渡す ---
  obj <- RTMB_Model$new(
    data       = data,
    par_list   = evaluated_par_list,
    log_prob   = safe_model,
    transform  = safe_transformed,
    generate   = safe_generate,
    par_names  = par_names,
    init       = init,
    view       = view,
    code       = code
  )

  return(obj)
}

#' ユーザーのコード(AST)を探索し、パッケージの関数に名前空間を自動付与する関数
#' @param expr 評価前のコード(AST)
#' @param pkg 対象のパッケージ名
#' @keywords internal
inject_namespace <- function(expr, pkg = "BayesRTMB") {
  # 単一の変数名や定数なら何もしない
  if (is.atomic(expr) || is.name(expr)) {
    return(expr)
  }

  # 関数呼び出し、演算子、ブロック ({...}, for, if など) の場合
  if (is.call(expr)) {
    # すでに pkg::func() のように名前空間が指定されている場合はスキップ
    if (identical(expr[[1]], quote(`::`)) || identical(expr[[1]], quote(`:::`))) {
      return(expr)
    }

    # 呼び出されている関数名を取得
    func_name <- as.character(expr[[1]])

    # func_name が単一の文字列である場合のみ処理 (クロージャの直接呼び出し等を回避)
    if (length(func_name) == 1) {
      # その関数が BayesRTMB パッケージの namespace 内に存在するかチェック
      # inherits = FALSE にすることで、base や stats の関数 (sum, log 等) を除外
      if (exists(func_name, envir = asNamespace(pkg), inherits = FALSE)) {
        # 存在すれば、 BayesRTMB::func_name にすり替える
        expr[[1]] <- call("::", as.name(pkg), as.name(func_name))
      }
    }

    # 関数の中身（引数や、for/if の中身）に対しても再帰的に適用する
    for (i in 2:length(expr)) {
      # 修正箇所: ASTにおける「空の引数」を正しく判定する
      if (!identical(expr[[i]], quote(expr=))) {
        expr[[i]] <- inject_namespace(expr[[i]], pkg)
      }
    }
  }

  return(expr)
}

#' StanライクなRTMBモデル定義ブロック (ハイブリッド対応版)
#'
#' @description
#' R標準のカンマ区切り記法と、Stan風のカンマなし記法({}の内側での記述)の両方に対応します。
#'
#' @param ... モデル定義ブロック
#' @return 未評価のコードブロックのリスト
#' @export
rtmb_code <- function(...) {
  args <- as.list(match.call())[-1]
  code_list <- list()
  valid_blocks <- c("data", "parameters", "transform", "model", "generate")

  # パターン1: 前者の書き方 (名前付き引数・カンマ区切り)
  if (!is.null(names(args))) {
    for (name in names(args)) {
      if (name == "") next
      if (name %in% valid_blocks) {
        code_list[[name]] <- args[[name]]
      } else {
        stop(sprintf("未知のブロック '%s' が指定されています。有効なブロックは %s です。",
                     name, paste(valid_blocks, collapse = ", ")), call. = FALSE)
      }
    }

  } else if (length(args) == 1 && is.null(names(args))) {
    # パターン2: 後者の書き方 (Stan風・カンマなし・全体を{}で囲む)
    ast <- args[[1]]
    if (is.call(ast) && identical(ast[[1]], as.name("{"))) {
      exprs <- as.list(ast)[-1]

      for (e in exprs) {
        if (is.null(e)) next

        if (is.call(e)) {
          block_name <- as.character(e[[1]])
          if (block_name %in% valid_blocks) {
            code_list[[block_name]] <- if (length(e) >= 2) e[[2]] else quote({})
          } else {
            stop(sprintf("未知のブロック '%s' が指定されています。有効なブロックは %s です。",
                         block_name, paste(valid_blocks, collapse = ", ")), call. = FALSE)
          }
        } else {
          stop(sprintf("rtmb_code内の記述が不正です: '%s'",
                       paste(deparse(e), collapse = " ")), call. = FALSE)
        }
      }
    } else {
      stop("rtmb_code() の記述形式が不正です。カンマで区切るか、全体を {} で囲んで記述してください。", call. = FALSE)
    }
  } else {
    stop("rtmb_code() の記述形式が不正です。カンマで区切るか、全体を {} で囲んで記述してください。", call. = FALSE)
  }

  code_list$env <- parent.frame()
  # rtmb_code の段階では名前空間の注入を行わず、そのままASTを返す
  return(code_list)
}


#' Model Code Wrapper for RTMB
#'
#' @param expr A block of code containing model description.
#' @param env Environment to assign to the generated function.
#' @return A standard R function object taking (dat, par).
#' @export
model_code <- function(expr, env = parent.frame()) {
  raw_expr <- substitute(expr)

  if (is.name(raw_expr)) {
    evaluated <- eval(raw_expr, envir = env)
    if (is.language(evaluated)) {
      raw_expr <- evaluated
    }
  }

  # --- ここで通常の数学関数等に名前空間を注入 ---
  raw_expr <- inject_namespace(raw_expr, pkg = "BayesRTMB")

  # 式を再帰的に走査し、`~` の記述を書き換える
  rewrite_formula <- function(x) {
    if (is.call(x)) {
      if (identical(x[[1]], as.name("~"))) {
        target <- x[[2]]
        dist_call <- x[[3]]

        if (!is.call(dist_call)) {
          stop(sprintf("The right side of '~' must be a distribution function call. (e.g., %s( ... ))",
                       as.character(dist_call)), call. = FALSE)
        }

        dist_name <- as.character(dist_call[[1]])
        dist_args <- as.list(dist_call[-1])

        name_lpdf <- paste0(dist_name, "_lpdf")
        name_lpmf <- paste0(dist_name, "_lpmf")

        exists_in_pkg <- function(fname) {
          requireNamespace("BayesRTMB", quietly = TRUE) &&
            exists(fname, mode = "function", envir = asNamespace("BayesRTMB"), inherits = FALSE)
        }

        use_pkg_namespace <- FALSE

        if (exists_in_pkg(name_lpdf)) {
          actual_name <- name_lpdf
          use_pkg_namespace <- TRUE
        } else if (exists_in_pkg(name_lpmf)) {
          actual_name <- name_lpmf
          use_pkg_namespace <- TRUE
        } else if (exists(name_lpdf, mode = "function", envir = env)) {
          actual_name <- name_lpdf
        } else if (exists(name_lpmf, mode = "function", envir = env)) {
          actual_name <- name_lpmf
        } else {
          actual_name <- name_lpdf # デフォルト
        }

        if (use_pkg_namespace) {
          func_call <- call("::", as.name("BayesRTMB"), as.name(actual_name))
        } else {
          func_call <- as.name(actual_name)
        }

        new_call <- as.call(c(
          as.name("<-"),
          as.name("lp"),
          as.call(c(
            as.name("+"),
            as.name("lp"),
            as.call(c(func_call, target, dist_args))
          ))
        ))
        return(new_call)
      }
      x[] <- lapply(x, rewrite_formula)
    }
    return(x)
  }

  processed_expr <- rewrite_formula(raw_expr)

  if (is.call(processed_expr) && identical(processed_expr[[1]], as.name("{"))) {
    expr_elements <- as.list(processed_expr)[-1]
  } else {
    expr_elements <- list(processed_expr)
  }

  body_list <- c(
    list(as.name("{")),
    quote(RTMB::getAll(dat, par)),
    quote(lp <- 0),
    unname(expr_elements),
    quote(return(lp))
  )
  body_expr <- as.call(body_list)

  args <- as.pairlist(alist(dat = , par = ))
  fn_expr <- call("function", args, body_expr)

  log_prob_fn <- eval(fn_expr, envir = env)
  attr(log_prob_fn, "raw_expr") <- raw_expr

  return(log_prob_fn)
}


#' Transformed Code Wrapper for RTMB
#'
#' @param expr A block of code containing calculations for transformed parameters.
#' @param env Environment to assign to the generated function.
#' @return A function taking (dat, par) that returns a named list.
#' @export
transform_code <- function(expr, env = parent.frame()) {
  raw_expr <- substitute(expr)

  # --- ここで通常の数学関数等に名前空間を注入 ---
  raw_expr <- inject_namespace(raw_expr, pkg = "BayesRTMB")

  # 1. 中括弧 {} の中身をフラットにする
  if (is.call(raw_expr) && identical(raw_expr[[1]], as.name("{"))) {
    expr_elements <- as.list(raw_expr)[-1]
  } else {
    expr_elements <- list(raw_expr)
  }

  # 2. 最後の要素が出力として明示されているか判定
  last_elem <- expr_elements[[length(expr_elements)]]

  is_explicit_return <- FALSE
  if (is.call(last_elem)) {
    if (identical(last_elem[[1]], as.name("list"))) {
      is_explicit_return <- TRUE
      ret_call <- last_elem
    } else if (identical(last_elem[[1]], as.name("return"))) {
      is_explicit_return <- TRUE
      ret_call <- last_elem[[2]]
    }
  } else if (is.name(last_elem)) {
    is_explicit_return <- TRUE
    ret_call <- last_elem
  }

  if (is_explicit_return) {
    expr_elements <- expr_elements[-length(expr_elements)]
  } else {
    find_assignments <- function(x) {
      if (is.call(x)) {
        if (identical(x[[1]], as.name("<-")) || identical(x[[1]], as.name("="))) {
          if (is.name(x[[2]])) return(as.character(x[[2]]))
        }
        return(unique(unlist(lapply(as.list(x), find_assignments))))
      }
      return(NULL)
    }
    defined_vars <- find_assignments(raw_expr)
    ret_list_args <- lapply(defined_vars, as.name)
    names(ret_list_args) <- defined_vars
    ret_call <- as.call(c(list(as.name("list")), ret_list_args))
  }

  # 3. 関数ボディの構築
  body_list <- c(
    list(as.name("{")),
    quote(RTMB::getAll(dat, par)),
    unname(expr_elements),
    list(as.call(list(as.name("return"), ret_call)))
  )
  body_expr <- as.call(body_list)

  # 4. 関数オブジェクトの生成
  args <- as.pairlist(alist(dat = , par = ))
  fn_expr <- call("function", args, body_expr)
  fn <- eval(fn_expr, envir = env)
  attr(fn, "raw_expr") <- raw_expr

  return(fn)
}

#' パラメータ定義用コードブロック
#'
#' @description
#' `rtmb_model` に渡すパラメータのリストを定義します。
#' `{}` で囲まれたブロック内で `変数名 = Dim(...)` の形式で記述することで、
#' 評価を遅延させ、モデル構築時の厳密なエラーチェックを可能にします。
#'
#' @param expr `{}` で囲まれたパラメータ定義の式
#' @return 評価が遅延されたパラメータのリスト
#' @export
parameters_code <- function(expr) {
  # ブロック内のコードを評価せず、式(AST)としてキャプチャ
  ast <- substitute(expr)

  # `{` で囲まれたブロックであるかをチェック
  if (!is.call(ast) || !identical(ast[[1]], as.name("{"))) {
    stop("parameters_code は {} で囲まれたブロックを受け取る必要があります。\n例: parameters_code({ beta = Dim(K) })", call. = FALSE)
  }

  exprs <- as.list(ast)[-1] # 先頭の `{` を除外
  param_list <- list()

  for (e in exprs) {
    # 空行はスキップ
    if (is.null(e)) next

    # 代入演算子 (= または <-) を使っているかをチェック
    if (is.call(e) && (identical(e[[1]], as.name("=")) || identical(e[[1]], as.name("<-")))) {
      var_name <- as.character(e[[2]])
      param_list[[var_name]] <- e[[3]] # 右辺の式 (Dim(...)など) をそのまま保存
    } else {
      stop(sprintf("parameters_code内の記述が不正です: '%s'\n「変数名 = Dim(...)」の形式で記述してください。",
                   paste(deparse(e), collapse = " ")), call. = FALSE)
    }
  }

  return(param_list)
}

#' Transformed Code Wrapper for RTMB
#'
#' @param expr A block of code containing calculations for transformed parameters.
#' @param env Environment to assign to the generated function.
#' @return A function taking (dat, par) that returns a named list.
#' @export
transform_code <- function(expr, env = parent.frame()) {
  raw_expr <- substitute(expr)

  # --- ここで通常の数学関数等に名前空間を注入 ---
  raw_expr <- inject_namespace(raw_expr, pkg = "BayesRTMB")

  # 1. 中括弧 {} の中身をフラットにする
  if (is.call(raw_expr) && identical(raw_expr[[1]], as.name("{"))) {
    expr_elements <- as.list(raw_expr)[-1]
  } else {
    expr_elements <- list(raw_expr)
  }

  # 2. 最後の要素が出力として明示されているか判定
  last_elem <- expr_elements[[length(expr_elements)]]

  is_explicit_return <- FALSE
  if (is.call(last_elem)) {
    if (identical(last_elem[[1]], as.name("list"))) {
      is_explicit_return <- TRUE
      ret_call <- last_elem
    } else if (identical(last_elem[[1]], as.name("return"))) {
      is_explicit_return <- TRUE
      ret_call <- last_elem[[2]]
    }
  } else if (is.name(last_elem)) {
    is_explicit_return <- TRUE
    ret_call <- last_elem
  }

  if (is_explicit_return) {
    expr_elements <- expr_elements[-length(expr_elements)]
  } else {
    find_assignments <- function(x) {
      if (is.call(x)) {
        if (identical(x[[1]], as.name("<-")) || identical(x[[1]], as.name("="))) {
          if (is.name(x[[2]])) return(as.character(x[[2]]))
        }
        return(unique(unlist(lapply(as.list(x), find_assignments))))
      }
      return(NULL)
    }
    defined_vars <- find_assignments(raw_expr)
    ret_list_args <- lapply(defined_vars, as.name)
    names(ret_list_args) <- defined_vars
    ret_call <- as.call(c(list(as.name("list")), ret_list_args))
  }

  # 3. 関数ボディの構築
  body_list <- c(
    list(as.name("{")),
    quote(RTMB::getAll(dat, par)),
    unname(expr_elements),
    list(as.call(list(as.name("return"), ret_call)))
  )
  body_expr <- as.call(body_list)

  # 4. 関数オブジェクトの生成
  args <- as.pairlist(alist(dat = , par = ))
  fn_expr <- call("function", args, body_expr)
  fn <- eval(fn_expr, envir = env)
  attr(fn, "raw_expr") <- raw_expr

  return(fn)
}
#' データとパラメータの事前検証
#'
#' @description
#' `rtmb_model` にデータを渡す前に、R特有のデータ型（data.frameなど）が混入していないか、
#' および欠損値の有無などをチェックし、エラーや警告を出力します。
#'
#' @param dat_list モデルに渡すデータのリスト（通常、行列や数値ベクトルを含む）。
#' @param par_list `Dim()` で定義されたパラメータのリスト。
#'
#' @return 検証に成功した場合は不可視の `NULL` を返します。問題がある場合は `stop()` で処理を中断、または `warning()` を発出します。
#'
#' @details
#' RTMBの自動微分エンジンは純粋な `matrix` や `numeric` を要求します。
#' ユーザーが誤って `data.frame` を渡した場合、計算グラフの構築時に不可解なエラーが発生するため、
#' この関数で事前に捕捉します。
validate_data <- function(dat_list, par_list) {
  # 1. データフレームのチェック
  for (name in names(dat_list)) {
    if (is.data.frame(dat_list[[name]])) {
      stop(sprintf(
        "【エラー】データ '%s' がデータフレーム(data.frame)のまま渡されています。\n行列演算が失敗するため、as.matrix() で行列に変換してから渡してください。",
        name
      ), call. = FALSE)
    }
  }

  # 2. NAのチェック
  for (name in names(dat_list)) {
    if (any(is.na(dat_list[[name]]))) {
      warning(sprintf("【警告】データ '%s' に欠損値(NA)が含まれています。予期せぬ動作を引き起こす可能性があります。", name), call. = FALSE)
    }
  }

  invisible(NULL)
}


#' 安全なRTMBモデルの構築（エラーメッセージ翻訳付き）
#'
#' @description
#' `rtmb_model` をラップし、内部の `MakeADFun` 実行時に発生する C++/RTMB 由来の
#' 難解なエラーメッセージを、ユーザーが理解しやすい日本語のヒントに翻訳して出力します。
#'
#' @param data `validate_data` を通過したデータのリスト。
#' @param parameters `Dim()` で定義されたパラメータのリスト。
#' @param model `model_code({})` で定義された尤度や事前分布のコードブロック。
#' @param generate `transform_code({})` で定義された生成量のコードブロック（省略可能）。
#'
#' @return 正常にコンパイルが完了した場合は、`rtmb_model` オブジェクト（R6クラスのインスタンス）を返します。
#'
#' @export
safe_rtmb_model <- function(data, parameters, model, generate = NULL) {
  # 事前検証を実行
  validate_data(data, parameters)

  tryCatch({
    # 実際のモデル構築処理
    obj <- rtmb_model(data, parameters, model, generate)
    return(obj)

  }, error = function(e) {
    err_msg <- conditionMessage(e)

    # ADクラス消失エラーの翻訳
    if (grepl("lost class attribute", err_msg) || grepl("Invalid argument to 'advector'", err_msg)) {
      stop(
        "【モデル構築エラー】自動微分(AD)の型が途中で消失しました。\n",
        "・原因: model_code 内で rep() や空の array() に対して for ループで逐次代入を行っている可能性があります。\n",
        "・対策: 行列のベクトル化計算を使用するか、初期化には numeric(M) などを利用してください。\n",
        "[元のエラー]: ", err_msg,
        call. = FALSE
      )
    }

    # 不正な演算エラーの翻訳
    if (grepl("illegal operation", err_msg) || grepl("not a valid 'advector'", err_msg)) {
      stop(
        "【モデル構築エラー】実行不可能な演算、または型の不整合が発生しました。\n",
        "・原因: 行列の掛け算(%*%)の左右で次元が合っていない、または Dim() の型指定 (CF_cov, lower_tri など) が実際の行列サイズと矛盾している可能性があります。\n",
        "[元のエラー]: ", err_msg,
        call. = FALSE
      )
    }

    # 数値/行列型エラーの翻訳
    if (grepl("requires numeric/complex matrix/vector", err_msg)) {
      stop(
        "【データ型エラー】数値ベクトルまたは行列が必要な箇所に、別の型が渡されています。\n",
        "・原因: 観測データやインデックスが data.frame や list になっていませんか？\n",
        "[元のエラー]: ", err_msg,
        call. = FALSE
      )
    }

    # 未知のエラーはそのまま出力
    stop("【予期せぬエラー】\n", err_msg, call. = FALSE)
  })
}


#' RTMBベースのGLMMラッパー関数
#' @param formula lme4スタイルのフォーミュラ (例: Y ~ X + (1 + X | GID))
#' @param data データフレーム
#' @param family 分布族の文字列
#' @param laplace 変量効果をラプラス近似で周辺化するかどうか (デフォルト: FALSE)
#' @param prior 事前分布のハイパーパラメータのリスト
#' @param init 初期値のリスト (指定しない場合はglmに基づく初期値が自動生成されます)
#' @export
rtmb_glmer <- function(formula, data, family = "gaussian", laplace = FALSE,
                       prior = list(
                         beta_sd = 10,
                         tau_rate = 1,
                         sigma_rate = 1,
                         lkj_eta = 1.0,
                         shape_rate = 1,
                         phi_rate = 1,
                         cutpoint_sd = 2.5
                       ),
                       init = NULL) {

  if (!requireNamespace("lme4", quietly = TRUE)) {
    stop("フォーミュラの解析に 'lme4' パッケージが必要です。")
  }

  if (is.null(lme4::findbars(formula))) {
    return(rtmb_glm(formula = formula, data = data, family = family, prior = prior))
  }

  # 1. フォーミュラのパース
  parsed <- lme4::lFormula(
    formula,
    data = data,
    control = lme4::lmerControl(
      check.nobs.vs.nlev = "ignore",
      check.nobs.vs.nRE  = "ignore"
    )
  )

  # --- 応答変数Yの型変換 ---
  Y <- model.response(parsed$fr)
  if (is.matrix(Y)) {
    if (ncol(Y) == 2 && family == "binomial") {
      trials <- as.numeric(Y[, 1] + Y[, 2])
      Y <- as.numeric(Y[, 1])
    } else if (ncol(Y) == 1) {
      Y <- as.numeric(Y[, 1])
      trials <- rep(1, length(Y))
    } else {
      stop("応答変数の行列形式が不正です。binomialの場合は cbind(成功数, 失敗数) を指定してください。")
    }
  } else {
    trials <- rep(1, length(Y))
    if (is.factor(Y)) {
      if (family %in% c("bernoulli", "binomial")) {
        Y <- as.numeric(Y) - 1
      } else {
        Y <- as.numeric(Y)
      }
    } else {
      Y <- as.numeric(Y)
    }
  }

  X <- parsed$X
  reTrms <- parsed$reTrms

  if (length(reTrms$Ztlist) > 1) {
    stop("現在、ラッパー関数は単一のグループ化変数のみに対応しています。")
  }

  if (family == "ordered" && "(Intercept)" %in% colnames(X)) {
    X <- X[, colnames(X) != "(Intercept)", drop = FALSE]
    if (ncol(X) == 0) {
      stop("順序ロジスティックモデルでは切片のみのモデルは現在サポートされていません。")
    }
  }

  fixed_names <- colnames(X)
  fixed_names[fixed_names == "(Intercept)"] <- "Intercept"
  ranef_names <- parsed$reTrms$cnms[[1]]
  ranef_names[ranef_names == "(Intercept)"] <- "Intercept"

  Zt <- as.matrix(reTrms$Ztlist[[1]])
  group_idx <- as.integer(reTrms$flist[[1]])
  num_groups <- length(levels(reTrms$flist[[1]]))
  num_ranef <- nrow(Zt) / num_groups
  offset <- model.offset(parsed$fr)

  # --- スマート初期化 (glmの利用) ---
  if (is.null(init)) {
    tryCatch({
      if (requireNamespace("reformulas", quietly = TRUE)) {
        fixed_formula <- reformulas::nobars(formula)
      } else {
        fixed_formula <- suppressWarnings(lme4::nobars(formula))
      }
      glm_fam <- switch(family,
                        "gaussian" = gaussian(), "student_t" = gaussian(),
                        "lognormal" = gaussian(link = "log"), "bernoulli" = binomial(),
                        "binomial" = binomial(), "poisson" = poisson(),
                        "neg_binomial" = poisson(), "gamma" = Gamma(link = "log"),
                        gaussian()
      )
      fit_glm <- suppressWarnings(glm(fixed_formula, data = data, family = glm_fam))
      init_b <- unname(coef(fit_glm))
      init_b[is.na(init_b)] <- 0
      init <- list(b = init_b)
    }, error = function(e) {
      init <- NULL
    })
  }

  N <- length(Y)
  Z_mat <- matrix(0, nrow = N, ncol = num_ranef)
  for (i in 1:N) {
    g <- group_idx[i]
    rows <- ((g - 1) * num_ranef + 1):(g * num_ranef)
    Z_mat[i, ] <- Zt[rows, i]
  }

  # 2. dataの準備 (静的解析を通すために num_categories等も追加)
  dat <- list(
    N = N, Y = Y, trials = trials, X = X, offset = offset,
    Z_mat = Z_mat, group_idx = group_idx,
    num_groups = num_groups, num_ranef = num_ranef, K = ncol(X),
    prior_beta_sd = prior$beta_sd, prior_tau_rate = prior$tau_rate,
    prior_sigma_rate = prior$sigma_rate, prior_lkj_eta = prior$lkj_eta,
    prior_shape_rate = prior$shape_rate, prior_phi_rate = prior$phi_rate,
    prior_cutpoint_sd = prior$cutpoint_sd
  )
  if (family == "ordered") {
    dat$num_categories <- length(unique(Y))
  }

  # 3. parameters ブロックの動的構築 (AST)
  param_exprs <- list()
  param_exprs[[length(param_exprs) + 1]] <- quote(b <- Dim(K))

  if (num_ranef == 1) {
    param_exprs[[length(param_exprs) + 1]] <- quote(sd <- Dim(num_ranef, lower = 0))
    param_exprs[[length(param_exprs) + 1]] <- quote(r <- Dim(num_groups, random = TRUE))
  } else {
    param_exprs[[length(param_exprs) + 1]] <- quote(sd <- Dim(num_ranef, lower = 0))
    param_exprs[[length(param_exprs) + 1]] <- quote(CF_cor <- Dim(c(num_ranef, num_ranef), type = "CF_corr"))
    param_exprs[[length(param_exprs) + 1]] <- quote(r <- Dim(c(num_groups, num_ranef), random = TRUE))
  }

  if (family %in% c("gaussian", "lognormal", "student_t")) {
    param_exprs[[length(param_exprs) + 1]] <- quote(sigma <- Dim(1, lower = 0))
  }
  if (family == "student_t") {
    param_exprs[[length(param_exprs) + 1]] <- quote(nu <- Dim(1, lower = 2))
  }
  if (family == "gamma") {
    param_exprs[[length(param_exprs) + 1]] <- quote(shape <- Dim(1, lower = 0))
  }
  if (family == "neg_binomial") {
    param_exprs[[length(param_exprs) + 1]] <- quote(phi <- Dim(1, lower = 0))
  }
  if (family == "ordered") {
    param_exprs[[length(param_exprs) + 1]] <- quote(cutpoints <- Dim(num_categories - 1, type = "ordered"))
  }
  param_ast <- as.call(c(list(as.name("{")), param_exprs))


  # 4. model ブロックの動的構築
  ll_expr <- switch(family,
                    "gaussian" = quote({ sigma ~ exponential(prior_sigma_rate); Y ~ normal(eta, sigma) }),
                    "lognormal" = quote({ sigma ~ exponential(prior_sigma_rate); Y ~ lognormal(eta, sigma) }),
                    "student_t" = quote({ sigma ~ exponential(prior_sigma_rate); nu ~ exponential(0.1); Y ~ student_t(nu, eta, sigma) }),
                    "gamma" = quote({ shape ~ exponential(prior_shape_rate); Y ~ gamma(shape, shape / exp(eta)) }),
                    "bernoulli" = quote({ Y ~ bernoulli_logit(eta) }),
                    "binomial" = quote({ Y ~ binomial_logit(trials, eta) }),
                    "poisson" = quote({ Y ~ poisson(exp(eta)) }),
                    "neg_binomial" = quote({ phi ~ exponential(prior_phi_rate); Y ~ neg_binomial_2(exp(eta), phi) }),
                    "ordered" = quote({ Y ~ ordered_logistic(eta, cutpoints); cutpoints ~ normal(0, prior_cutpoint_sd) })
  )

  if (num_ranef > 1) {
    common_expr <- quote({
      b ~ normal(0, prior_beta_sd)
      sd ~ exponential(prior_tau_rate)
      CF_cor ~ lkj_CF_corr(prior_lkj_eta)
      for (j in 1:num_groups) { r[j, ] ~ multi_normal_CF(rep(0, num_ranef), rep(1, num_ranef), CF_cor) }
      eta <- X %*% b
      for (i in 1:N) { eta[i] <- eta[i] + sum(Z_mat[i, ] * r[group_idx[i], ] * sd) }
    })
  } else {
    common_expr <- quote({
      b ~ normal(0, prior_beta_sd)
      sd ~ exponential(prior_tau_rate)
      r ~ normal(0, 1)
      eta <- X %*% b + Z_mat[,1] * r[group_idx] * sd
    })
  }

  offset_expr <- if (!is.null(offset)) quote({eta <- eta + offset}) else quote({})

  model_ast <- as.call(c(list(as.name("{")), as.list(common_expr)[-1], as.list(offset_expr)[-1], as.list(ll_expr)[-1]))

  # 5. transform ブロックの構築
  tran_ast <- if (num_ranef > 1) quote({ cor <- CF_cor %*% t(CF_cor) }) else NULL

  # --- 新しい rtmb_code への組み立て ---
  code_obj <- list(parameters = param_ast, model = model_ast)
  if (!is.null(tran_ast)) code_obj$transform <- tran_ast

  par_names_list <- list(b = fixed_names, sd = ranef_names)
  if (num_ranef > 1) par_names_list$cor <- ranef_names

  obj <- rtmb_model(
    data = dat,
    code = code_obj,
    par_names = par_names_list,
    init = init,
    view = c("b", "sd", "cor")
  )

  obj$formula <- formula
  obj$raw_data <- data
  obj$family <- family

  return(obj)
}


#' RTMBベースのGLMラッパー関数 (変量効果なし)
#'
#' @param formula フォーミュラ (例: Y ~ X1 + X2)
#' @param data データフレーム
#' @param family 分布族の文字列
#' @param prior 事前分布のハイパーパラメータのリスト
#' @export
rtmb_glm <- function(formula, data, family = "gaussian",
                     prior = list(
                       beta_sd = 10,
                       sigma_rate = 1,
                       shape_rate = 1,
                       phi_rate = 1,
                       cutpoint_sd = 2.5
                     )) {

  mf <- model.frame(formula, data)
  Y <- model.response(mf)
  X <- model.matrix(formula, mf)

  if (family == "ordered" && "(Intercept)" %in% colnames(X)) {
    X <- X[, colnames(X) != "(Intercept)", drop = FALSE]
    if (ncol(X) == 0) {
      stop("順序ロジスティックモデルでは切片のみのモデルは現在サポートされていません。")
    }
  }

  if (is.matrix(Y)) {
    if (ncol(Y) == 2 && family == "binomial") {
      trials <- as.numeric(Y[, 1] + Y[, 2])
      Y <- as.numeric(Y[, 1])
    } else if (ncol(Y) == 1) {
      Y <- as.numeric(Y[, 1])
      trials <- rep(1, length(Y))
    } else {
      stop("応答変数の行列形式が不正です。binomialの場合は cbind(成功数, 失敗数) を指定してください。")
    }
  } else {
    trials <- rep(1, length(Y))
    if (is.factor(Y)) {
      if (family %in% c("bernoulli", "binomial")) {
        Y <- as.numeric(Y) - 1
      } else {
        Y <- as.numeric(Y)
      }
    } else {
      Y <- as.numeric(Y)
    }
  }

  N <- length(Y)
  fixed_names <- colnames(X)
  fixed_names[fixed_names == "(Intercept)"] <- "Intercept"
  offset <- model.offset(mf)

  # 1. dataの準備
  dat <- list(
    N = N, Y = Y, trials = trials, X = X, offset = offset, K = ncol(X),
    prior_beta_sd = prior$beta_sd, prior_sigma_rate = prior$sigma_rate,
    prior_shape_rate = prior$shape_rate, prior_phi_rate = prior$phi_rate,
    prior_cutpoint_sd = prior$cutpoint_sd
  )
  if (family == "ordered") {
    dat$num_categories <- length(unique(Y))
  }

  # 2. parameters ブロックの動的構築 (AST)
  param_exprs <- list()
  param_exprs[[length(param_exprs) + 1]] <- quote(b <- Dim(K))

  if (family %in% c("gaussian", "lognormal", "student_t")) {
    param_exprs[[length(param_exprs) + 1]] <- quote(sigma <- Dim(1, lower = 0))
  }
  if (family == "student_t") {
    param_exprs[[length(param_exprs) + 1]] <- quote(nu <- Dim(1, lower = 2))
  }
  if (family == "gamma") {
    param_exprs[[length(param_exprs) + 1]] <- quote(shape <- Dim(1, lower = 0))
  }
  if (family == "neg_binomial") {
    param_exprs[[length(param_exprs) + 1]] <- quote(phi <- Dim(1, lower = 0))
  }
  if (family == "ordered") {
    param_exprs[[length(param_exprs) + 1]] <- quote(cutpoints <- Dim(num_categories - 1, type = "ordered"))
  }
  param_ast <- as.call(c(list(as.name("{")), param_exprs))

  # 3. model ブロックの動的構築
  ll_expr <- switch(family,
                    "gaussian" = quote({ Y ~ normal(eta, sigma); sigma ~ exponential(prior_sigma_rate) }),
                    "lognormal" = quote({ Y ~ lognormal(eta, sigma); sigma ~ exponential(prior_sigma_rate) }),
                    "student_t" = quote({ Y ~ student_t(nu, eta, sigma); sigma ~ exponential(prior_sigma_rate); nu ~ exponential(0.1) }),
                    "gamma" = quote({ Y ~ gamma(shape, shape / exp(eta)); shape ~ exponential(prior_shape_rate) }),
                    "bernoulli" = quote({ Y ~ bernoulli_logit(eta) }),
                    "binomial" = quote({ Y ~ binomial_logit(trials, eta) }),
                    "poisson" = quote({ Y ~ poisson(exp(eta)) }),
                    "neg_binomial" = quote({ Y ~ neg_binomial_2(exp(eta), phi); phi ~ exponential(prior_phi_rate) }),
                    "ordered" = quote({ Y ~ ordered_logistic(eta, cutpoints); cutpoints ~ normal(0, prior_cutpoint_sd) })
  )

  common_expr <- quote({
    b ~ normal(0, prior_beta_sd)
    eta <- as.vector(X %*% b)
  })

  offset_expr <- if (!is.null(offset)) quote({eta <- eta + offset}) else quote({})
  model_ast <- as.call(c(list(as.name("{")), as.list(common_expr)[-1], as.list(offset_expr)[-1], as.list(ll_expr)[-1]))

  # --- 新しい rtmb_code への組み立て ---
  code_obj <- list(parameters = param_ast, model = model_ast)

  obj <- rtmb_model(
    data = dat,
    code = code_obj,
    par_names = list(b = fixed_names)
  )

  obj$formula <- formula
  obj$raw_data <- data
  obj$family <- family

  return(obj)
}

#' RTMB-based Factor Analysis Wrapper
#'
#' @description
#' Performs exploratory factor analysis (EFA) using RTMB. It supports standard
#' rotation methods (e.g., varimax, promax) as well as regularized factor analysis
#' using a Spike-and-Slab Prior (SSP) for estimating sparse loading matrices.
#'
#' @param data Observation data frame or matrix (N x J).
#' @param nfactors Number of factors (K).
#' @param rotate String specifying the rotation method (e.g., "varimax", "promax", "ssp"). If NULL, no rotation is applied. Specifying "ssp" performs regularized factor analysis.
#' @param score Logical; if TRUE, factor scores are calculated in the generate block (default is FALSE).
#' @param prior List of hyperparameters for prior distributions. `ssp_ratio` represents the proportion of non-zero loadings per factor when "ssp" is specified.
#' @param init List of initial values. If not provided, initial values are automatically generated based on PCA or the psych package.
#' @export
rtmb_fa <- function(data, nfactors = 1, rotate = NULL, score = FALSE,
                    prior = list(mean_sd = 10, loadings_sd = 1, sd_rate = 10, ssp_ratio = 0.25),
                    init = NULL) {

  Y <- as.matrix(data)
  N <- nrow(Y)
  J <- ncol(Y)
  K <- nfactors

  var_names <- colnames(data)
  if (is.null(var_names)) var_names <- paste0("V", 1:J)

  if (K >= J) stop("因子の数(K)は観測変数の数(J)より小さくする必要があります。")

  Y_bar <- apply(Y, 2, mean)
  S_Y <- cov(Y) * (N - 1)

  # SSPモデルかどうかの判定
  is_ssp <- !is.null(rotate) && rotate == "ssp"

  if (is_ssp) {
    if (is.null(prior$ssp_ratio)) prior$ssp_ratio <- 0.25

    dat_fa <- list(
      N = N, J = J, K_factors = K,
      Y_bar = Y_bar, S_Y = S_Y,
      prior_mean_sd = prior$mean_sd, prior_sd_rate = prior$sd_rate,
      ssp_ratio = prior$ssp_ratio
    )
    if (score) dat_fa$Y <- Y

    # SSP用の初期値自動生成 (Base RのPCAとpromaxを利用)
    if (is.null(init)) {
      tryCatch({
        # 1. PCAによる初期負荷量の抽出
        eig <- eigen(S_Y / (N - 1))
        L_pca <- eig$vectors[, 1:K, drop = FALSE] %*% diag(sqrt(eig$values[1:K]), nrow = K, ncol = K)
        var_Y <- diag(S_Y / (N - 1))

        if (K > 1) {
          # 2. R標準の stats::promax による斜交回転
          pm <- stats::promax(L_pca, m = 4)
          init_Lambda <- unclass(pm$loadings)
          T_mat <- pm$rotmat

          # 因子間相関行列 Phi = (T^T T)^-1
          # (数値誤差を防ぐため cov2cor で厳密な相関行列化)
          Phi <- cov2cor(solve(t(T_mat) %*% T_mat))
          init_CF_Omega <- t(chol(Phi))
        } else {
          init_Lambda <- L_pca
          Phi <- matrix(1, nrow = 1, ncol = 1)
          init_CF_Omega <- matrix(1, nrow = 1, ncol = 1)
        }

        # 3. 独自分散 (sd) の推定
        h2_raw <- rowSums(init_Lambda * (init_Lambda %*% Phi))
        init_sd <- sqrt(pmax(var_Y - h2_raw, 0.01 * var_Y))

        # 4. 標準化負荷量から包含確率 (r) の初期値を設定
        L_std <- init_Lambda / sqrt(var_Y)
        init_r <- ifelse(abs(L_std) > 0.2, 0.9, 0.1)

        init <- list(
          mean = Y_bar,
          Lambda_star = init_Lambda,
          sd = init_sd,
          CF_Omega = init_CF_Omega,
          r = init_r,
          tau = matrix(1.0, nrow = J, ncol = K)
        )
      }, error = function(e) {
        stop("初期値の自動生成に失敗しました。init 引数で手動で初期値を与えてください。詳細: ", conditionMessage(e))
      })
    }

    param_ast <- quote({
      mean = Dim(dim = J)
      Lambda_star = Dim(c(J, K_factors))
      r = Dim(c(J, K_factors), lower = 0.001, upper = 0.999)
      tau = Dim(c(J, K_factors), lower = 0)
      sd = Dim(J, lower = 0)
      CF_Omega = Dim(c(K_factors, K_factors), type = "CF_corr")
    })

    tran_ast <- quote({
      loadings_raw <- Lambda_star * r * tau
      h2 <- rowSums(loadings_raw * (loadings_raw %*% CF_Omega))
      var_Y <- h2 + sd^2
      sd_Y <- sqrt(var_Y)
      loadings <- loadings_raw / sd_Y
      fa_cor <- CF_Omega %*% t(CF_Omega)
    })

    model_ast <- quote({
      S_Y ~ sufficient_multi_normal_fa(N, Y_bar, mean, sd, loadings_raw %*% CF_Omega)
      mean ~ normal(0, prior_mean_sd)
      sd ~ exponential(prior_sd_rate)
      CF_Omega ~ lkj_CF_corr(1)

      mu_r <- log(ssp_ratio / (1 - ssp_ratio))

      for (j in 1:J) {
        for (k in 1:K_factors) {
          r[j, k] ~ logit_normal(mu_r, 3)
          tau[j, k] ~ exponential(1)
          Lambda_star[j, k] ~ laplace(0, 1)
        }
      }
    })

    base_gq <- quote({
      Sigma <- loadings_raw %*% fa_cor %*% t(loadings_raw) + diag(sd^2)
      var_total <- diag(Sigma)
      var_common <- rowSums(loadings_raw * (loadings_raw %*% CF_Omega))
      communality <- var_common / var_total
      out <- list(communality = communality)
    })

    score_expr <- if (score) {
      quote({
        Y_c <- matrix(0, nrow = N, ncol = J)
        for (i in 1:N) Y_c[i, ] <- Y[i, ] - mean
        out$score <- Y_c %*% solve(Sigma, loadings_raw %*% fa_cor)
      })
    } else quote({})

    ret_expr <- quote({ return(out) })
    gq_ast <- as.call(c(list(as.name("{")), as.list(base_gq)[-1], as.list(score_expr)[-1], as.list(ret_expr)[-1]))

    code_args <- list(parameters = param_ast, transform = tran_ast, model = model_ast, generate = gq_ast)
    code_obj <- eval(as.call(c(list(as.name("rtmb_code")), code_args)))

    p_names <- list(
      mean = var_names,
      Lambda_star = var_names,
      r = var_names,
      tau = var_names,
      sd = var_names,
      CF_Omega = paste0("Factor", 1:K),
      loadings_raw = var_names,
      loadings = var_names,
      fa_cor = paste0("Factor", 1:K),
      communality = var_names
    )
    if (score) {
      ind_names <- rownames(data)
      if (is.null(ind_names)) ind_names <- paste0("Id", 1:N)
      p_names[["score"]] <- list(ind_names, paste0("Factor", 1:K))
    }

    target_view <- c("loadings", "sd", "fa_cor")

    obj <- rtmb_model(
      data = dat_fa,
      code = code_obj,
      par_names = p_names,
      init = init,
      view = target_view
    )

    return(obj)

  } else {
    # --- 既存の回転ロジック (varimax, promax 等) ---
    dat_fa <- list(
      N = N, J = J, K_factors = K,
      Y_bar = Y_bar, S_Y = S_Y,
      prior_mean_sd = prior$mean_sd, prior_loadings_sd = prior$loadings_sd, prior_sd_rate = prior$sd_rate
    )
    if (score) dat_fa$Y <- Y

    if (is.null(init)) {
      tryCatch({
        eig <- eigen(S_Y / (N - 1))
        L_pca <- eig$vectors[, 1:K, drop = FALSE] %*% diag(sqrt(eig$values[1:K]), nrow=K, ncol=K)
        L_top <- L_pca[1:K, , drop = FALSE]
        qr_res <- qr(t(L_top))
        Q_mat <- qr.Q(qr_res)
        init_loadings <- L_pca %*% Q_mat
        init_sd <- pmax(diag(S_Y / (N - 1)) - rowSums(init_loadings^2), 0.01)^0.5

        for (j in 1:J) {
          for (k in 1:K) {
            if (j < k) init_loadings[j, k] <- 0
          }
        }
        init <- list(mean = Y_bar, loadings_raw = init_loadings, sd = init_sd)
      }, error = function(e) { init <- NULL })
    }

    param_ast <- quote({
      mean <- Dim(dim = J)
      loadings_raw <- Dim(dim = c(J, K_factors), type = "lower_tri")
      sd <- Dim(dim = J, lower = 0)
    })

    tran_ast <- quote({
      h2 <- rowSums(loadings_raw^2)
      var_Y <- h2 + sd^2
      sd_Y <- sqrt(var_Y)
      loadings <- loadings_raw / sd_Y
    })

    model_ast <- quote({
      S_Y ~ sufficient_multi_normal_fa(N, Y_bar, mean, sd, loadings_raw)
      mean ~ normal(0, prior_mean_sd)
      sd ~ exponential(prior_sd_rate)
      loadings_raw ~ lower_tri_normal(0, prior_loadings_sd)
    })

    base_gq <- quote({
      Sigma <- loadings_raw %*% t(loadings_raw) + diag(sd^2)
      var_total <- diag(Sigma)
      var_common <- rowSums(loadings_raw^2)
      communality <- var_common / var_total
      out <- list(communality = communality)
    })

    if (!is.null(rotate)) {
      rot_loadings_name <- paste0("loadings_", rotate)

      if (exists(rotate, mode = "function")) {
        rot_fn <- match.fun(rotate)
        fn_call <- as.name(rotate)
      } else if (requireNamespace("GPArotation", quietly = TRUE) &&
                 exists(rotate, where = asNamespace("GPArotation"), mode = "function")) {
        rot_fn <- getFromNamespace(rotate, "GPArotation")
        fn_call <- call("::", as.name("GPArotation"), as.name(rotate))
      } else {
        stop("Rotation function not found: ", rotate)
      }

      dummy_L <- matrix(rnorm(J * K), J, K)
      test_rot <- rot_fn(dummy_L)

      is_matrix_rot <- is.matrix(test_rot)
      has_phi <- !is_matrix_rot && !is.null(test_rot$Phi)

      if (is_matrix_rot) {
        rot_expr <- bquote({
          rot_obj <- .(fn_call)(loadings)
          rot_mat <- unclass(rot_obj)
          out[[.(rot_loadings_name)]] <- rot_mat
        })
        score_expr <- if (score) quote({
          Y_c <- matrix(0, nrow = N, ncol = J)
          for (i in 1:N) Y_c[i, ] <- Y[i, ] - mean
          out$score <- Y_c %*% solve(Sigma, rot_mat)
        }) else quote({})
      } else {
        if (has_phi) {
          rot_expr <- bquote({
            rot_obj <- .(fn_call)(loadings)
            rot_mat <- unclass(rot_obj$loadings)
            out$fa_cor <- rot_obj$Phi
            out[[.(rot_loadings_name)]] <- rot_mat
          })
          score_expr <- if (score) quote({
            Y_c <- matrix(0, nrow = N, ncol = J)
            for (i in 1:N) Y_c[i, ] <- Y[i, ] - mean
            out$score <- Y_c %*% solve(Sigma, rot_mat %*% rot_obj$Phi)
          }) else quote({})
        } else {
          rot_expr <- bquote({
            rot_obj <- .(fn_call)(loadings)
            rot_mat <- unclass(rot_obj$loadings)
            out[[.(rot_loadings_name)]] <- rot_mat
          })
          score_expr <- if (score) quote({
            Y_c <- matrix(0, nrow = N, ncol = J)
            for (i in 1:N) Y_c[i, ] <- Y[i, ] - mean
            out$score <- Y_c %*% solve(Sigma, rot_mat)
          }) else quote({})
        }
      }
    } else {
      has_phi <- FALSE
      rot_expr <- quote({})
      score_expr <- if (score) {
        quote({
          Y_c <- matrix(0, nrow = N, ncol = J)
          for (i in 1:N) Y_c[i, ] <- Y[i, ] - mean
          out$score <- Y_c %*% solve(Sigma, loadings)
        })
      } else quote({})
    }

    ret_expr <- quote({ return(out) })

    gq_ast <- as.call(c(list(as.name("{")), as.list(base_gq)[-1], as.list(rot_expr)[-1], as.list(score_expr)[-1], as.list(ret_expr)[-1]))

    code_args <- list(parameters = param_ast, transform = tran_ast, model = model_ast, generate = gq_ast)
    code_obj <- eval(as.call(c(list(as.name("rtmb_code")), code_args)))

    p_names <- list(
      mean = var_names,
      loadings_raw = var_names,
      sd = var_names,
      loadings = var_names,
      communality = var_names
    )
    if (!is.null(rotate)) {
      p_names[[paste0("loadings_", rotate)]] <- var_names
      if (has_phi) p_names[["fa_cor"]] <- paste0("Factor", 1:K)
    }
    if (score) {
      ind_names <- rownames(data)
      if (is.null(ind_names)) ind_names <- paste0("Id", 1:N)
      p_names[["score"]] <- list(ind_names, paste0("Factor", 1:K))
    }

    target_view <- if (!is.null(rotate)) c(paste0("loadings_", rotate), "sd", "fa_cor") else c("loadings", "sd", "fa_cor")

    obj <- rtmb_model(
      data = dat_fa,
      code = code_obj,
      par_names = p_names,
      init = init,
      view = target_view
    )

    return(obj)
  }
}


#' 相関行列 (多変量正規分布) 推定ラッパー
#'
#' @param data 観測データフレームまたは行列 (N x P)
#' @param prior 事前分布のハイパーパラメータのリスト
#' @export
rtmb_cor <- function(data, prior = list(lkj_eta = 1.0, mu_sd = 10, sigma_rate = 1.0)) {

  Y <- as.matrix(data)
  N <- nrow(Y)
  P <- ncol(Y)

  var_names <- colnames(data)
  if (is.null(var_names)) var_names <- paste0("V", 1:P)

  dat <- list(
    N = N, P = P, Y = Y,
    prior_lkj_eta = prior$lkj_eta, prior_sigma_rate = prior$sigma_rate, prior_mu_sd = prior$mu_sd
  )

  param_ast <- quote({
    mean   <- Dim(P)
    sd     <- Dim(P, lower = 0)
    CF_cor <- Dim(c(P, P), type = "CF_corr")
  })

  model_ast <- quote({
    mean ~ normal(0, prior_mu_sd)
    sd ~ exponential(prior_sigma_rate)
    CF_cor ~ lkj_CF_corr(prior_lkj_eta)
    for(i in 1:N) {
      Y[i, ] ~ multi_normal_CF(mean, sd, CF_cor)
    }
  })

  tran_ast <- quote({
    cor <- CF_cor %*% t(CF_cor)
  })

  # --- 新しい rtmb_code への組み立て ---
  code_obj <- list(parameters = param_ast, model = model_ast, transform = tran_ast)

  obj <- rtmb_model(
    data = dat,
    code = code_obj,
    par_names = list(mean = var_names, sd = var_names, cor = var_names),
    view = c("cor")
  )

  return(obj)
}
